import React, { useEffect, useRef, useState } from 'react';
import { useStaticQuery, graphql } from 'gatsby';
import { getSrc } from 'gatsby-plugin-image';
import PropTypes from 'prop-types';
import anime from 'animejs';
import { useAnimationPlayPause, useAnimationCanceled } from './animationHooks';

function AnimationTimeline({
  svg,
  cursorDefault,
  cursorPointer,
  popupContainer,
  popup,
  duration,
  transitionTime,
  cb = () => {},
}) {
  const intro = anime.timeline({
    complete: cb,
  });
  return intro
    .add({
      targets: [svg],
      opacity: [0, 1],
      duration: transitionTime,
      easing: 'easeInOutSine',
    })
    .add({
      targets: [cursorDefault, cursorPointer],
      translateX: [511.857, 361.857],
      translateY: [88.5, 350.5],
      duration: 800,
      easing: 'easeInOutSine',
    })
    .add(
      {
        targets: cursorDefault,
        opacity: [1, 0],
        duration: 100,
        easing: 'easeInOutSine',
      },
      '-=100',
    )
    .add(
      {
        targets: cursorPointer,
        opacity: [0, 1],
        duration: 100,
        easing: 'easeInOutSine',
      },
      '-=100',
    ) // relative offset
    .add(
      {
        targets: popupContainer,
        opacity: [0, 1],
        duration: 300,
        easing: 'easeInOutSine',
      },
      '+=300',
    ) // relative offset
    .add(
      {
        targets: [popup],
        translateX: [91, 91],
        translateY: [86 + 50, 86],
        duration: 300,
        easing: 'easeInOutSine',
      },
      '-=300',
    )
    .add({
      targets: [svg],
      opacity: [1, 1],
      duration: duration,
      easing: 'easeInOutSine',
    })
    .add({
      targets: [svg],
      opacity: [1, 0],
      duration: transitionTime,
      easing: 'easeInOutSine',
    });
}

